arguments.content:
# Start ssh-agent in Nushell if no agent socket is available.
# This is a direct Nushell equivalent of:
#   eval $(ssh-agent -s)
#
# It starts a fresh agent and loads SSH_AUTH_SOCK / SSH_AGENT_PID
# into the current Nushell environment.

if ($env.SSH_AUTH_SOCK? | default "") == "" {
  let out = (ssh-agent -s | complete)

  if $out.exit_code != 0 {
    error make { msg: $"ssh-agent failed: ($out.stderr)" }
  }

  let sock = ($out.stdout | parse -r 'SSH_AUTH_SOCK=(?P<sock>[^;]+);' | get sock | first?)
  let pid = ($out.stdout | parse -r 'SSH_AGENT_PID=(?P<pid>\d+);' | get pid | first?)

  if ($sock | default "") != "" {
    $env.SSH_AUTH_SOCK = $sock
  }

  if ($pid | default "") != "" {
    $env.SSH_AGENT_PID = $pid
  }
}

